import{_ as d,o as a,c as r,a2 as e}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"丹药炼制","description":"","frontmatter":{},"headers":[],"relativePath":"guide/danyao.md","filePath":"guide/danyao.md","lastUpdated":null}'),h={name:"guide/danyao.md"};function n(o,t,l,s,i,b){return a(),r("div",null,[...t[0]||(t[0]=[e(`<h1 id="丹药炼制" tabindex="-1">丹药炼制 <a class="header-anchor" href="#丹药炼制" aria-label="Permalink to &quot;丹药炼制&quot;">​</a></h1><p>炼丹是修仙过程中极为重要的辅助手段。突破丹助你突破瓶颈，渡劫丹护你安然渡劫，治疗丹和恢复丹保障你的生存。</p><hr><h2 id="丹药类型" tabindex="-1">丹药类型 <a class="header-anchor" href="#丹药类型" aria-label="Permalink to &quot;丹药类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>丹药</th><th>用途</th><th>最高品质效果</th></tr></thead><tbody><tr><td><strong>突破丹</strong></td><td>提高突破成功率</td><td>极品：+65% 成功率</td></tr><tr><td><strong>渡劫丹</strong></td><td>提高渡劫成功率</td><td>极品：+60% 成功率</td></tr><tr><td><strong>治疗丹</strong></td><td>恢复生命值</td><td>极品：瞬间回复大量HP</td></tr><tr><td><strong>恢复丹</strong></td><td>恢复灵气值</td><td>极品：恢复 3,000 灵气</td></tr></tbody></table><hr><h2 id="品质等级" tabindex="-1">品质等级 <a class="header-anchor" href="#品质等级" aria-label="Permalink to &quot;品质等级&quot;">​</a></h2><p>所有丹药分为四个品质：</p><table tabindex="0"><thead><tr><th>品质</th><th>成功率</th><th>灵气消耗</th><th>修为消耗</th><th>炼制耗时</th><th>失败伤害</th><th>全服广播</th><th>雷电特效</th></tr></thead><tbody><tr><td><strong>下阶</strong></td><td>最高</td><td>最低</td><td>0</td><td>10秒</td><td>0</td><td>❌</td><td>❌</td></tr><tr><td><strong>中等</strong></td><td>较高</td><td>中等</td><td>少量</td><td>15秒</td><td>0</td><td>❌</td><td>❌</td></tr><tr><td><strong>高级</strong></td><td>中等</td><td>较高</td><td>较多</td><td>30秒</td><td>有</td><td>✅</td><td>✅</td></tr><tr><td><strong>极品</strong></td><td>最低</td><td>最高</td><td>大量</td><td>60秒</td><td>较高</td><td>✅</td><td>✅</td></tr></tbody></table><blockquote><p>⚠️ <strong>重要</strong>：高级和极品丹药炼制失败会对玩家造成伤害！炼丹前请确保血量充足。</p></blockquote><hr><h2 id="突破丹详解" tabindex="-1">突破丹详解 <a class="header-anchor" href="#突破丹详解" aria-label="Permalink to &quot;突破丹详解&quot;">​</a></h2><p>提高突破成功率的丹药，是修仙者最重要的丹药之一。</p><table tabindex="0"><thead><tr><th>品质</th><th>灵气消耗</th><th>修为消耗</th><th>成功率</th><th>效果值</th><th>失败伤害</th><th>耗时</th></tr></thead><tbody><tr><td>下阶</td><td>300</td><td>0</td><td>70%</td><td>+20%</td><td>0</td><td>10秒</td></tr><tr><td>中等</td><td>600</td><td>20</td><td>60%</td><td>+30%</td><td>0</td><td>15秒</td></tr><tr><td>高级</td><td>1,200</td><td>80</td><td>45%</td><td>+45%</td><td>30</td><td>30秒</td></tr><tr><td>极品</td><td>2,500</td><td>200</td><td>25%</td><td>+65%</td><td>80</td><td>60秒</td></tr></tbody></table><blockquote><p>💡 基础突破丹加成（全局配置）：+25%。使用突破丹后在此基础叠加。</p></blockquote><h3 id="收益分析" tabindex="-1">收益分析 <a class="header-anchor" href="#收益分析" aria-label="Permalink to &quot;收益分析&quot;">​</a></h3><ul><li><strong>下阶</strong>：安全但效果有限，适合练气/筑基期</li><li><strong>中等</strong>：性价比最高，金丹/元婴期推荐</li><li><strong>高级</strong>：效果显著但风险中等，化神/渡劫期推荐</li><li><strong>极品</strong>：效果最强但仅 25% 成功率 + 80 伤害，建议配合保护措施</li></ul><hr><h2 id="渡劫丹详解" tabindex="-1">渡劫丹详解 <a class="header-anchor" href="#渡劫丹详解" aria-label="Permalink to &quot;渡劫丹详解&quot;">​</a></h2><p>专门用于渡劫时提高成功率，减少天雷伤害。</p><table tabindex="0"><thead><tr><th>品质</th><th>灵气消耗</th><th>修为消耗</th><th>成功率</th><th>效果值</th><th>失败伤害</th><th>耗时</th></tr></thead><tbody><tr><td>下阶</td><td>400</td><td>10</td><td>65%</td><td>+15%</td><td>0</td><td>10秒</td></tr><tr><td>中等</td><td>800</td><td>40</td><td>55%</td><td>+25%</td><td>0</td><td>15秒</td></tr><tr><td>高级</td><td>1,600</td><td>120</td><td>40%</td><td>+40%</td><td>35</td><td>30秒</td></tr><tr><td>极品</td><td>3,000</td><td>280</td><td>20%</td><td>+60%</td><td>100</td><td>60秒</td></tr></tbody></table><blockquote><p>⚡ 渡劫丹是<strong>金丹及以上境界必备</strong>！尤其大乘/飞升期天雷伤害极高，极品渡劫丹几乎必须。</p></blockquote><hr><h2 id="治疗丹详解" tabindex="-1">治疗丹详解 <a class="header-anchor" href="#治疗丹详解" aria-label="Permalink to &quot;治疗丹详解&quot;">​</a></h2><p>瞬间恢复生命值。</p><table tabindex="0"><thead><tr><th>品质</th><th>灵气消耗</th><th>修为消耗</th><th>成功率</th><th>失败伤害</th><th>耗时</th></tr></thead><tbody><tr><td>下阶</td><td>200</td><td>0</td><td>75%</td><td>0</td><td>10秒</td></tr><tr><td>中等</td><td>400</td><td>15</td><td>65%</td><td>0</td><td>15秒</td></tr><tr><td>高级</td><td>800</td><td>60</td><td>50%</td><td>25</td><td>30秒</td></tr><tr><td>极品</td><td>1,800</td><td>150</td><td>30%</td><td>60</td><td>60秒</td></tr></tbody></table><hr><h2 id="恢复丹详解" tabindex="-1">恢复丹详解 <a class="header-anchor" href="#恢复丹详解" aria-label="Permalink to &quot;恢复丹详解&quot;">​</a></h2><p>恢复灵气值。灵气耗尽时使用可快速回满继续战斗。</p><table tabindex="0"><thead><tr><th>品质</th><th>灵气消耗</th><th>修为消耗</th><th>成功率</th><th>效果值</th><th>失败伤害</th><th>耗时</th></tr></thead><tbody><tr><td>下阶</td><td>250</td><td>0</td><td>70%</td><td>200灵气</td><td>0</td><td>10秒</td></tr><tr><td>中等</td><td>500</td><td>20</td><td>60%</td><td>500灵气</td><td>0</td><td>15秒</td></tr><tr><td>高级</td><td>1,000</td><td>80</td><td>45%</td><td>1,200灵气</td><td>28</td><td>30秒</td></tr><tr><td>极品</td><td>2,200</td><td>200</td><td>25%</td><td>3,000灵气</td><td>70</td><td>60秒</td></tr></tbody></table><hr><h2 id="炼丹机制" tabindex="-1">炼丹机制 <a class="header-anchor" href="#炼丹机制" aria-label="Permalink to &quot;炼丹机制&quot;">​</a></h2><h3 id="全局参数" tabindex="-1">全局参数 <a class="header-anchor" href="#全局参数" aria-label="Permalink to &quot;全局参数&quot;">​</a></h3><table tabindex="0"><thead><tr><th>参数</th><th>值</th><th>说明</th></tr></thead><tbody><tr><td>炼丹冷却</td><td>60秒</td><td>炼制任意丹药后需等待</td></tr><tr><td>修炼丹持续时间</td><td>90秒</td><td>修炼类丹药效果持续90秒</td></tr><tr><td>修仙等级加成</td><td>+1%/级</td><td>每1级修仙等级提高1%成功率</td></tr><tr><td>全局突破丹基础加成</td><td>+25%</td><td>突破丹的保底加成</td></tr></tbody></table><h3 id="成功率计算" tabindex="-1">成功率计算 <a class="header-anchor" href="#成功率计算" aria-label="Permalink to &quot;成功率计算&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>实际炼制成功率 = 丹药品质基础成功率 + (修仙等级 × 1%)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>实际突破总加成  = 全局基础25% + 突破丹品质效果值 + 灵根加成 + 天道加成</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><strong>炼丹成功率示例</strong>：</p><table tabindex="0"><thead><tr><th>修仙等级</th><th>下阶突破丹(70%)</th><th>极品渡劫丹(20%)</th><th>极品恢复丹(25%)</th></tr></thead><tbody><tr><td>10级</td><td>80%</td><td>30%</td><td>35%</td></tr><tr><td>20级</td><td>90%</td><td>40%</td><td>45%</td></tr><tr><td>30级</td><td>100%</td><td>50%</td><td>55%</td></tr><tr><td>50级</td><td>100%</td><td>70%</td><td>75%</td></tr><tr><td>80级</td><td>100%</td><td>100%</td><td>100%</td></tr></tbody></table><h3 id="失败伤害总览" tabindex="-1">失败伤害总览 <a class="header-anchor" href="#失败伤害总览" aria-label="Permalink to &quot;失败伤害总览&quot;">​</a></h3><table tabindex="0"><thead><tr><th>品质</th><th>突破丹</th><th>渡劫丹</th><th>治疗丹</th><th>恢复丹</th></tr></thead><tbody><tr><td>下阶</td><td>0</td><td>0</td><td>0</td><td>0</td></tr><tr><td>中等</td><td>0</td><td>0</td><td>0</td><td>0</td></tr><tr><td>高级</td><td>30</td><td>35</td><td>25</td><td>28</td></tr><tr><td>极品</td><td>80</td><td>100</td><td>60</td><td>70</td></tr></tbody></table><blockquote><p>⚠️ **极品渡劫丹失败扣 100 HP！**务必在满血状态下炼制，或提前吃治疗丹保命。</p></blockquote><h3 id="极品丹药炼制技巧" tabindex="-1">极品丹药炼制技巧 <a class="header-anchor" href="#极品丹药炼制技巧" aria-label="Permalink to &quot;极品丹药炼制技巧&quot;">​</a></h3><ol><li><strong>提升修仙等级</strong> — 每级 +1% 成功率，80级后所有丹药100%安全</li><li><strong>天道境界加成</strong> — 天道眷顾及以上提供额外保护</li><li><strong>备好治疗丹</strong> — 先炼下阶治疗丹（75%成功率，不受伤）再挑战极品</li><li><strong>天道试炼事件期间</strong> — 突破成功率 +15%，此时炼突破丹事半功倍</li></ol><h3 id="修为消耗注意" tabindex="-1">修为消耗注意 <a class="header-anchor" href="#修为消耗注意" aria-label="Permalink to &quot;修为消耗注意&quot;">​</a></h3><p>中等及以上品质丹药炼制会消耗修为（最多消耗280修为），请确保修为充足以免影响突破进度。</p><hr><h2 id="炼丹指令" tabindex="-1">炼丹指令 <a class="header-anchor" href="#炼丹指令" aria-label="Permalink to &quot;炼丹指令&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/liandan &lt;丹药名&gt; &lt;品质&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>示例：</p><ul><li><code>/liandan 突破丹 中等</code> — 炼制中等级突破丹（55%总加成）</li><li><code>/liandan 渡劫丹 极品</code> — 炼制极品质渡劫丹（85%总加成）</li><li><code>/liandan 治疗丹 下阶</code> — 炼制下阶治疗丹（安全无风险）</li><li><code>/liandan 恢复丹 高级</code> — 炼制高级恢复丹（恢复1200灵气）</li></ul>`,50)])])}const u=d(h,[["render",n]]);export{p as __pageData,u as default};
